import random
from lfu_service import LFUCache
from models import KeyNotFoundError

# Brute-force reference LFU with LRU tie-break, tracking insertion/use order
class RefLFU:
    def __init__(self, cap):
        self.cap=cap; self.store={}; self.freq={}; self.tick=0; self.last={}
    def get(self, k):
        if k not in self.store: raise KeyNotFoundError
        self.freq[k]+=1; self.tick+=1; self.last[k]=self.tick
        return self.store[k]
    def put(self, k, v):
        if k in self.store:
            self.store[k]=v; self.freq[k]+=1; self.tick+=1; self.last[k]=self.tick
            return
        if len(self.store)>=self.cap:
            # evict min freq, tie-break by oldest last-use
            victim=min(self.store, key=lambda x:(self.freq[x], self.last[x]))
            del self.store[victim]; del self.freq[victim]; del self.last[victim]
        self.store[k]=v; self.freq[k]=1; self.tick+=1; self.last[k]=self.tick

random.seed(42)
for trial in range(2000):
    cap=random.randint(1,5)
    a=LFUCache(cap); b=RefLFU(cap)
    for _ in range(40):
        k=random.randint(0,7)
        if random.random()<0.5:
            try: ra=a.get(k)
            except KeyNotFoundError: ra='MISS'
            try: rb=b.get(k)
            except KeyNotFoundError: rb='MISS'
            assert (ra=='MISS')==(rb=='MISS'), f'trial {trial} get mismatch k={k}'
        else:
            v=random.randint(0,1000)
            a.put(k,v); b.put(k,v)
        assert set(a.snapshot().keys())==set(b.store.keys()), f'trial {trial} keyset mismatch: {set(a.snapshot().keys())} vs {set(b.store.keys())}'
print('Differential test passed: 2000 trials, core matches brute-force LFU+LRU reference')
